(function(){
	let catItem = $('.catalogue__link'),
			galItem = $('.gallery__item'),
			close = $('.popup__close');
	catItem.on('click',function(e){
		e.preventDefault()
		let _this = $(this),
				parent = _this.closest('.catalogue__item'),
				popup = parent.find('.catalogue__popup'),
				img = parent.find('.gallery__img-pic').first(),
				firstImg = img.closest('.gallery__item'),
				display = parent.find('.gallery__display');
				firstImg.addClass('active')
								.siblings()
								.removeClass('active');
				display.attr('src',img.attr('src'));
				popup.fadeIn();
	});
	galItem.on('click',function(){
		let _this = $(this),
				galImg = _this.find('.gallery__img-pic'),
				parent = _this.closest('.popup__left'),
				display = parent.find('.gallery__display'),
				src = galImg.attr('src');
			display.attr('src',src);
		if(_this.hasClass('active')){
				_this.siblings()
						 .removeClass('active');
		}else{
			_this.addClass('active')
					 .siblings()
					 .removeClass('active');
		}

	});

	close.on('click',function(){
		var _this = $(this);
		_this.closest('.catalogue__popup').fadeOut()
	});


})();
[].forEach.call(document.querySelectorAll('.gallery__img-pic[data-src]'),function(img){
	img.setAttribute('src',img.getAttribute('data-src'));
	img.onload = function(){
		img.removeAttribute('data-src');
	};
});


$(document).ready(function(){

	(function(){
		var _thisForma;
		$('.btn__form').on('click', function(){
					$('.form__first').fadeIn();
					_thisForma = $('.form__first');
		});

		$('.form__close').on('click',function(){
			$('.form__first').fadeOut();
			$('.popup-thanks').fadeOut();
			$('.popup-err').fadeOut();
		});
	
		$('#form__btn-thanks').on('click', function() {
			$('.popup-thanks').fadeOut();
		});
		$('#form__btn-err').on('click', function() {
			$('.popup-err').fadeOut();
			_thisForma.fadeIn();
		});
	})();
	(function(){
		$('#first-form').submit(function(e) {
			var $mainForm = $(this);
			$.ajax({
				type: $mainForm.attr('method'),
				url: $mainForm.attr('action'),
				data: $mainForm.serialize()
			}).done(function() {
				$('.form__first').fadeOut();
				$('.popup-thanks').fadeIn();
				$('form[name=first-form]').trigger('reset');
			}).fail(function() {
				$('.form__first').fadeOut();
				$('.popup-err').fadeIn();
				$('form[name=first-form]').trigger('reset');
			});
			//отмена действия по умолчанию для кнопки submit
			e.preventDefault();
		});
		$('#questions__form').submit(function(e) {
			var $mainForm = $(this);
			$.ajax({
				type: $mainForm.attr('method'),
				url: $mainForm.attr('action'),
				data: $mainForm.serialize()
			}).done(function() {
				$('.form__first').fadeOut();
				$('.popup-thanks').fadeIn();
				$('form[name=questions__form]').trigger('reset');
			}).fail(function() {
				$('.form__first').fadeOut();
				$('.popup-err').fadeIn();
				$('form[name=questions__form]').trigger('reset');
			});
			//отмена действия по умолчанию для кнопки submit
			e.preventDefault();
		});
	})();
});
// .btn__form // вызов формы
// btn__form-sumbit // вызов только или успешной или проваленой отпраки
window.addEventListener('load',function(){
			let hed = document.querySelector('#header'),
					obj = $('#offsetHeight').offset().top;
			
    window.addEventListener('scroll',function(){
    let wScroll = this.scrollY;
    if(wScroll > obj){
      hed.classList.add('menu__scroll');
    } else {
      hed.classList.remove('menu__scroll');
    }
		});
	(function(){
		$('.header__menu').on('click',function(){
			let _this = $(this);
			if(_this.hasClass('active')){
				_this.removeClass('active')
				$('.menu__wrapper').fadeOut(300,function(){
					if($(this).css('display') == 'none'){
						$(this).removeAttr('style');
						}
				});
			}else {
				_this.addClass('active')
				$('.menu__wrapper').fadeIn(300);
			}
		});
	})();
	(function(){
		$("#nav__menu").on("click","a", function (event) {
			event.preventDefault();
			//идентификатор блока с атрибута href
			var id  = $(this).attr('href'),
			//высоту от начала страницы до блока на который ссылается якорь
				top = $(id).offset().top;
			//анимация перехода на расстояние - top за 1500 мс
			$('body,html').animate({scrollTop: top}, 1500);
		});
	})();
});
(function(){
	$('#hero__form').submit(function(e) {
		var $mainForm = $(this);

		$.ajax({
			type: $mainForm.attr('method'),
			url: $mainForm.attr('action'),
			data: $mainForm.serialize()
		}).done(function() {
			$('.form__first').fadeOut();
			window.open('/assets/download/partner.pdf');
			$('form[name=hero__form]').trigger('reset');
		}).fail(function() {
			$('.form__first').fadeOut();
			$('form[name=hero__form]').trigger('reset');
		});
		//отмена действия по умолчанию для кнопки submit
		e.preventDefault();
	});
})();
